using Firstronic.Framework.Entities;

using Firstronic.Core.Entities.App.First;
using Firstronic.Framework.Data;
using Firstronic.Framework.Attributes;

using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.ComponentModel.DataAnnotations.Schema;
using System.Linq;
using System.Web;
using System.Web.Mvc;
using System.Data.SqlClient;
using System.Data;

namespace Firstronic.Areas.Manage.Controllers
{
  [Authorize(Roles = "BF Administrator")]
  public class FacilitiesController : BaseSecurityController
  {
    private readonly DataContext db;

    #region Ctor

    public FacilitiesController()
    {

      db = new DataContext();
    }

    #endregion Ctor

    // GET: Manage/Departament
    public ActionResult Index()
    {
      var model = db.Database.SqlQuery<tbl_Common_Facilities>($@"SELECT f.[Facility_Key],f.[Facility_name]  FROM [dbo].[Common_Facilities] f ").ToArray().ToList().AsQueryable();

      return View(model);
    }

    // GET: Manage/Departament/Create
    public ActionResult Create()
    {
      var model = new tbl_Common_Facilities();
      return View(model);
    }

    // POST: Manage/Departament/Create
    // Create
    [HttpPost]
    [ValidateInput(false)]
    [ValidateAntiForgeryToken]
    [MultipleButtonAction(Name = "action", Argument = "Create")]
    public ActionResult Create(tbl_Common_Facilities model)
    {
      if (ModelState.IsValid)
      {
        SqlParameter[] parameters = new SqlParameter[]{
          new SqlParameter("@Facility_Key",SqlDbType.Int){Value =model.Facility_Key},
          new SqlParameter("@Facility_Name",SqlDbType.NVarChar){Value =(model.Facility_Name ?? "").ToString()}
        };

        var result = Firstronic.Framework.Queries.InsertQuery($@"INSERT INTO [dbo].[Common_Facilities]
                   (Facility_Key,
				Facility_Name)
				VALUES
                   (@Facility_Key,
				@Facility_Name)", parameters );

        if (result > 0)
        {
          this.NotifySuccess("Successfully saved.");
          return RedirectToAction("Edit", new { Id = result });
        }
        else if (result == 0)
        {
          this.NotifyError("Record can not save!");
          return RedirectToAction("Index");
        }
        else
        {
          this.NotifyError("Error in database.");
          return RedirectToAction("Index");
        }
      }

      return View(model);
    }

    // GET: Manage/Departament/Edit/5
    public ActionResult Edit(int id)
    {
      SqlParameter[] parameters = new SqlParameter[]{
        new SqlParameter("@Id",SqlDbType.Int){Value = id},
      };

      var model0 = Framework.Functions.Utilies.ConvertTo<tbl_Common_Facilities>(Firstronic.Framework.Queries.GetDatatableFromQuery("SELECT *   FROM Common_Facilities WHERE Facility_Key=@Id ", parameters)).FirstOrDefault();

      if (model0 == null)
      {
        this.NotifyError("Not found.");
        return RedirectToAction("Index");
      }

      var Main_Facility_List = new List<SelectListItem>();
      Main_Facility_List = Framework.Functions.Dropdowns.GetBooleanList(null);
      var model = new tbl_Common_Facilities
      {
        Facility_Key = model0.Facility_Key,
        Facility_Name = model0.Facility_Name
      };
      return View(model);
    }

    // POST: Manage/Departament/Edit/5
    // Edit
    [HttpPost]
    [ValidateAntiForgeryToken]
    [MultipleButtonAction(Name = "action", Argument = "Edit")]
    public ActionResult Edit(tbl_Common_Facilities model)
    {
      if (ModelState.IsValid)
      {
        SqlParameter[] parameters = new SqlParameter[]{
          new SqlParameter("@Id",SqlDbType.Int){Value = model.Facility_Key},
        };

        var record = Framework.Functions.Utilies.ConvertTo<tbl_Common_Facilities>(Firstronic.Framework.Queries.GetDatatableFromQuery("SELECT *   FROM Common_Facilities WHERE Facility_Key=@Id ", parameters)).FirstOrDefault();

        if (record is null)
        {
          this.NotifyError("Record not found.");
          return RedirectToAction("Index");
        }

        SqlParameter[] updateParameters = new SqlParameter[]{
          new SqlParameter("@Facility_Key",SqlDbType.Int){Value = model.Facility_Key},
          new SqlParameter("@Facility_Name",SqlDbType.NVarChar){Value =(model.Facility_Name ?? "").ToString()}
        };

        var result = Firstronic.Framework.Queries.ExecuteQuery("UPDATE Common_Facilities SET  Facility_Name = @Facility_Name WHERE Facility_Key = @Facility_Key", updateParameters);

        if (result > 0)
          this.NotifySuccess("Successfully saved.");
        else if (result == 0)
          this.NotifySuccess("Record can not save!");
        else
          this.NotifyError("Error in database.");

        return RedirectToAction("Edit", new { name = record.Facility_Name });
      }

      return View(model);
    }

    // Delete [Disable]
    [HttpPost]
    [ValidateAntiForgeryToken]
    [MultipleButtonAction(Name = "action", Argument = "Delete")]
    public ActionResult Delete(tbl_Common_Facilities model)
    {
      if (ModelState.IsValid)
      {
        SqlParameter[] parameters = new SqlParameter[]{
          new SqlParameter("@Id",SqlDbType.Int){Value = model.Facility_Key},
        };

        var record = Framework.Functions.Utilies.ConvertTo<tbl_Common_Facilities>(Firstronic.Framework.Queries.GetDatatableFromQuery("SELECT *   FROM Common_Facilities WHERE Facility_Key=@Id ", parameters)).FirstOrDefault();

        if (record is null)
        {
          this.NotifyError("Record not found.");
          return RedirectToAction("Index");
        }

        SqlParameter[] delParameters = new SqlParameter[]{
          new SqlParameter("@Id",SqlDbType.Int){Value = model.Facility_Key},
        };

        var result = Firstronic.Framework.Queries.ExecuteQuery("DELETE FROM Common_Facilities " +
           " WHERE Facility_Key=@Id ", delParameters);

        if (result > 0)
          this.NotifySuccess("Successfully saved.");
        else if (result == 0)
          this.NotifyError("Record can not save!");
        else
          this.NotifyError("Error in database.");

        return RedirectToAction("Index");
      }

      return View(model);
    }
  }
}
```

## Key Template Patterns for BuildingController

This controller follows the standard BeFirst Portal CRUD pattern:

**Structure:**
- Constructor with `DataContext db`
- `Index()` - List all records
- `Create()` GET/POST - Add new records
- `Edit(id)` GET/POST - Update existing records
- `Delete()` POST - Remove records

**Technical Patterns:**
- `[Authorize(Roles = "BF Administrator")]` for area-wide security
- `BaseSecurityController` inheritance
- `SqlParameter[]` for all queries (parameterized SQL)
- `Framework.Queries.InsertQuery()`, `ExecuteQuery()`, `GetDatatableFromQuery()`
- `Framework.Functions.Utilies.ConvertTo<T>()` for DataTable → model conversion
- `this.NotifySuccess()` / `this.NotifyError()` for user feedback
- `[MultipleButtonAction]` attribute for multiple submit buttons

**Database Table:**
- `Common_Facilities` table with `Facility_Key` (PK) and `Facility_Name`

You can use this as a template for your BuildingController, adapting the entity name, table name, and fields as needed.
